#include <stdio.h>
#include <stdlib.h>
#include <math.h>

typedef struct {
    float x, y, z;
} vec3;

typedef struct {
    vec3 origin;
    vec3 direction;
} ray;

typedef struct {
    vec3 center;
    float radius;
    vec3 color;
} sphere;

typedef struct {
    vec3 point;
    vec3 normal;
    vec3 color;
} plane;

vec3 vec3_create(float x, float y, float z) {
    vec3 v = {x, y, z};
    return v;
}

vec3 vec3_add(vec3 a, vec3 b) {
    return vec3_create(a.x + b.x, a.y + b.y, a.z + b.z);
}

vec3 vec3_sub(vec3 a, vec3 b) {
    return vec3_create(a.x - b.x, a.y - b.y, a.z - b.z);
}

vec3 vec3_mul(vec3 a, float s) {
    return vec3_create(a.x * s, a.y * s, a.z * s);
}

float vec3_dot(vec3 a, vec3 b) {
    return a.x * b.x + a.y * b.y + a.z * b.z;
}

vec3 vec3_normalize(vec3 v) {
    float len = sqrt(vec3_dot(v, v));
    return vec3_mul(v, 1.0f / len);
}

float sphere_intersect(sphere s, ray r) {
    vec3 oc = vec3_sub(r.origin, s.center);
    float a = vec3_dot(r.direction, r.direction);
    float b = 2.0f * vec3_dot(oc, r.direction);
    float c = vec3_dot(oc, oc) - s.radius * s.radius;
    float discriminant = b * b - 4 * a * c;

    if (discriminant < 0) return -1;

    float t = (-b - sqrt(discriminant)) / (2.0f * a);
    if (t < 0) return -1;

    return t;
}

float plane_intersect(plane p, ray r) {
    float denom = vec3_dot(p.normal, r.direction);
    if (fabs(denom) < 1e-6) return -1;

    vec3 p0l0 = vec3_sub(p.point, r.origin);
    float t = vec3_dot(p0l0, p.normal) / denom;
    if (t < 0) return -1;

    return t;
}

vec3 trace(ray r) {
    float t_min = 1e20;
    vec3 color = vec3_create(0, 0, 0);
    int hit = 0;

    // Sphere 1
    sphere s1 = {vec3_create(-2, 0, -5), 1.0f, vec3_create(1, 0, 0)};
    float t1 = sphere_intersect(s1, r);
    if (t1 > 0 && t1 < t_min) {
        t_min = t1;
        color = s1.color;
        hit = 1;
    }

    // Sphere 2
    sphere s2 = {vec3_create(2, 0, -5), 1.0f, vec3_create(0, 1, 0)};
    float t2 = sphere_intersect(s2, r);
    if (t2 > 0 && t2 < t_min) {
        t_min = t2;
        color = s2.color;
        hit = 1;
    }

    // Floor plane
    plane floor = {vec3_create(0, -1, 0), vec3_create(0, 1, 0), vec3_create(0.5, 0.5, 0.5)};
    float t3 = plane_intersect(floor, r);
    if (t3 > 0 && t3 < t_min) {
        t_min = t3;
        color = floor.color;
        hit = 1;
    }

    if (!hit) {
        // Sky gradient
        float t = 0.5f * (r.direction.y + 1.0f);
        color = vec3_add(vec3_mul(vec3_create(1, 1, 1), 1.0f - t), 
                        vec3_mul(vec3_create(0.5, 0.7, 1.0), t));
    }

    return color;
}

void write_image(FILE* fp, vec3* image, int width, int height) {
    fprintf(fp, "P3\n%d %d\n255\n", width, height);

    for (int y = 0; y < height; y++) {
        for (int x = 0; x < width; x++) {
            int idx = y * width + x;
            vec3 color = image[idx];

            // Clamp and convert to 8-bit
            int r = (int)(255.99f * fmax(0, fmin(1, color.x)));
            int g = (int)(255.99f * fmax(0, fmin(1, color.y)));
            int b = (int)(255.99f * fmax(0, fmin(1, color.z)));

            fprintf(fp, "%d %d %d\n", r, g, b);
        }
    }
}

int main() {
    int width = 800;
    int height = 600;

    printf("Creating high-resolution image: %dx%d\n", width, height);
    printf("This will be downsampled with ffmpeg after rendering\n");
    printf("Rendering high-resolution image...\n");

    vec3* image = malloc(width * height * sizeof(vec3));
    if (!image) {
        fprintf(stderr, "Failed to allocate image\n");
        return 1;
    }

    // Camera setup
    vec3 origin = vec3_create(0, 0, 0);
    float aspect_ratio = (float)width / (float)height;
    float viewport_height = 2.0f;
    float viewport_width = aspect_ratio * viewport_height;
    float focal_length = 1.0f;

    vec3 horizontal = vec3_create(viewport_width, 0, 0);
    vec3 vertical = vec3_create(0, viewport_height, 0);
    vec3 lower_left_corner = vec3_sub(vec3_sub(vec3_sub(origin, 
        vec3_mul(horizontal, 0.5f)), vec3_mul(vertical, 0.5f)), 
        vec3_create(0, 0, focal_length));

    // Render loop
    for (int y = 0; y < height; y++) {
        if (y % 10 == 0) {
            float progress = 100.0f * y / height;
            printf("Progress: %.1f%%\r", progress);
            fflush(stdout);
        }

        for (int x = 0; x < width; x++) {
            float u = (float)x / (width - 1);
            float v = (float)(height - 1 - y) / (height - 1);

            vec3 direction = vec3_sub(vec3_add(vec3_add(lower_left_corner, 
                vec3_mul(horizontal, u)), vec3_mul(vertical, v)), origin);

            ray r = {origin, vec3_normalize(direction)};
            vec3 color = trace(r);

            image[y * width + x] = color;
        }
    }

    printf("Progress: 100.0%%\n");
    printf("Rendering complete\n");

    // Write image
    FILE* fp = fopen("image.ppm", "w");
    if (!fp) {
        fprintf(stderr, "Failed to open output file\n");
        free(image);
        return 1;
    }

    write_image(fp, image, width, height);
    fclose(fp);
    free(image);

    printf("Wrote image to image.ppm\n");
    printf("Done.\n");

    return 0;
}
EOF
